import os
from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core
from src.utils.prism_config import (
    resolve_cfg, get_departments, resolve_dept_folder, get_entity_scenefiles_root
)

class PrismGetEntityPathNode(BaseNode):
    name = "Prism: Get Entity Path"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity", "dict")
        self.add_input("department", "string", widget_type="text", default="")
        self.add_input("task", "string", widget_type="text", default="")
        self.add_output("entity_root", "string")
        self.add_output("dept_path", "string")
        self.add_output("task_path", "string")
        self.add_output("found", "bool")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        entity = inputs.get('entity') or {}
        dept_input = (inputs.get('department') or '').strip()
        task_input = (inputs.get('task') or '').strip()
        defaults = {'entity_root': '', 'dept_path': '', 'task_path': '', 'found': False}
        entity_root = entity.get('path', '').strip()
        if not entity_root:
            self.log_error('Entity has no path — connect output from prism_get_shot_by_sequence.')
            return defaults
        if not os.path.isdir(entity_root):
            self.log_error(f'Entity path does not exist: {entity_root}')
            return defaults
        cfg_path = resolve_cfg(core=core, entity=entity)
        entity_type = entity.get('type', 'shot')
        dept_defs = get_departments(core, cfg_path, entity_type)
        self.log_info(f'cfg={cfg_path}, dept_defs={[(d["abbreviation"], d["name"]) for d in dept_defs]}')
        dept_path = ''
        task_path = ''
        if dept_input:
            scenes_root = get_entity_scenefiles_root(entity, core, cfg_path)
            if not scenes_root:
                self.log_error(f'No Scenefiles folder in {entity_root}')
                return {'entity_root': entity_root, 'dept_path': '', 'task_path': '', 'found': True}
            dept_abbrev = resolve_dept_folder(dept_input, dept_defs) or dept_input.lower()
            for entry in os.scandir(scenes_root):
                if entry.is_dir() and entry.name.lower() == dept_abbrev:
                    dept_path = entry.path
                    break
            if dept_path:
                self.log_info(f"dept '{dept_input}' (abbrev='{dept_abbrev}') -> {dept_path}")
            else:
                available = sorted(e.name for e in os.scandir(scenes_root) if e.is_dir())
                self.log_error(f"Dept '{dept_input}' (abbrev='{dept_abbrev}') not found — available: {available}")
        if task_input and dept_path and os.path.isdir(dept_path):
            available_tasks = sorted(e.name for e in os.scandir(dept_path) if e.is_dir())
            self.log_info(f'available tasks: {available_tasks}')
            for entry in os.scandir(dept_path):
                if entry.is_dir() and entry.name.lower() == task_input.lower():
                    task_path = entry.path
                    break
            if task_path:
                self.log_info(f"task '{task_input}' -> {task_path}")
            else:
                self.log_error(f"Task '{task_input}' not found — available: {available_tasks}")
        self.log_info(f'entity_root={entity_root}')
        return {'entity_root': entity_root, 'dept_path': dept_path,
                'task_path': task_path, 'found': True}

def register_node():
    return PrismGetEntityPathNode
